900	/* DO I = start TO end; ... END; codegen.
901	 * Lowers to: I = start; WHILE (I <= end) { body; I = I + 1; }
902	 * AST: nd_name = loop var, nd_left = start, nd_ival = end expr, nd_right = body */
903	void cg_do_count(int node) {
904	    int lbl_top;
905	    int lbl_end;
906	
907	    lbl_top = emit_new_label();
908	    lbl_end = emit_new_label();
909	
910	    /* I = start: evaluate start expr into r0, store to loop var */
911	    cg_expr(nd_left[node]);
912	    cg_store_var(node);  /* nd_name[node] = loop var name */
913	
914	    /* Loop header label */
915	    emit_label(lbl_top);
916	
917	    /* Compare: load I into r0, save, eval end into r0, then compare */
918	    cg_load_var(node);       /* r0 = I */
919	    emit_instr("push    r0");
920	    cg_expr(nd_ival[node]);  /* r0 = end */
921	    emit_instr("mov     r1,r0");  /* r1 = end */
922	    emit_instr("pop     r0");     /* r0 = I */
923	
924	    /* Branch to end if I > end (i.e., end < I) */
925	    emit_instr("cls     r1,r0");  /* carry if end < I */
926	    emit_str(EMIT_INDENT);
927	    emit_str("bc      ");
928	    emit_label_ref(lbl_end);
929	    emit_nl();
930	
931	    /* Loop body */
932	    cg_stmt(nd_right[node]);
933	
934	    /* Increment: I = I + 1 */
935	    cg_load_var(node);
936	    emit_instr("lc      r1,1");
937	    emit_instr("add     r0,r1");
938	    cg_store_var(node);
939	
940	    /* Branch back to header */
941	    emit_str(EMIT_INDENT);
942	    emit_str("jmp     ");
943	    emit_label_ref(lbl_top);
944	    emit_nl();
945	
946	    /* End label */
947	    emit_label(lbl_end);
948	}
