952	/* Emit code for a single statement node */
953	void cg_stmt(int node) {
954	    if (node == NODE_NULL) return;
955	
956	    if (nd_kind[node] == NODE_ASSIGN) {
957	        cg_assign(node);
958	    } else if (nd_kind[node] == NODE_RETURN) {
959	        /* Evaluate return expression into r0 (if present) */
960	        if (nd_left[node] != NODE_NULL) {
961	            cg_expr(nd_left[node]);
962	        }
963	        /* Epilogue emitted by caller at procedure end.
964	         * For early returns, emit epilogue inline. */
965	        emit_epilogue();
966	    } else if (nd_kind[node] == NODE_CALL) {
967	        /* Bare CALL statement (result in r0 discarded) */
968	        cg_call(node);
969	    } else if (nd_kind[node] == NODE_BLOCK) {
970	        cg_block(node);
971	    } else if (nd_kind[node] == NODE_IF) {
972	        /* IF/THEN/ELSE: evaluate condition, branch on false */
973	        cg_if(node);
974	    } else if (nd_kind[node] == NODE_DO_WHILE) {
975	        /* DO WHILE: loop with condition at top */
976	        cg_do_while(node);
977	    } else if (nd_kind[node] == NODE_DO_COUNT) {
978	        /* DO I = start TO end: counted loop */
979	        cg_do_count(node);
980	    } else if (nd_kind[node] == NODE_DCL) {
981	        /* Local DCL: no code emission needed (handled by layout) */
982	    } else {
983	        cg_error("unsupported statement kind");
984	        emit_comment("ERROR: unsupported statement");
985	        emit_str(EMIT_INDENT);
986	        emit_str("; kind=");
987	        emit_int(nd_kind[node]);
988	        emit_nl();
989	    }
990	}
