1006	/* Emit code for a complete procedure.
1007	 * proc_node is a NODE_PROC with:
1008	 *   nd_name  = procedure name
1009	 *   nd_left  = first parameter (linked via nd_next)
1010	 *   nd_right = body (BLOCK node)
1011	 *   nd_ival  = option flags (OPT_FREESTANDING, OPT_NAKED, OPT_LEAF)
1012	 *   nd_stor  = return type
1013	 *
1014	 * Layout must be performed first via layout_proc(). */
1015	
1016	void cg_proc(int proc_node) {
1017	    int opts;
1018	    int frame_sz;
1019	    int has_body;
1020	    int body;
1021	
1022	    if (proc_node == NODE_NULL) return;
1023	    if (nd_kind[proc_node] != NODE_PROC) {
1024	        cg_error("expected PROC node");
1025	        return;
1026	    }
1027	
1028	    opts = nd_ival[proc_node];
1029	    body = nd_right[proc_node];
1030	
1031	    /* Ensure we're in .text section */
1032	    emit_text_section();
1033	
1034	    /* Emit .globl directive and label */
1035	    if (nd_name[proc_node]) {
1036	        emit_global(nd_name[proc_node]);
1037	        emit_named_label(nd_name[proc_node]);
1038	    }
1039	
1040	    /* NAKED procedures: no prologue/epilogue, body is raw */
1041	    if (opts & 2) {
1042	        /* OPT_NAKED */
1043	        emit_comment("NAKED procedure -- no prologue/epilogue");
1044	        cg_block(body);
1045	        return;
1046	    }
1047	
1048	    /* Standard prologue: push fp, push r2, push r1, mov fp,sp */
1049	    emit_prologue();
1050	
1051	    /* Allocate stack space for locals (sub sp, frame_size) */
1052	    frame_sz = layout_frame_size;
1053	    if (frame_sz > 0) {
1054	        if (frame_sz >= -128 && frame_sz <= 127) {
1055	            emit_str(EMIT_INDENT);
1056	            emit_str("lc      r0,");
1057	            emit_int(frame_sz);
1058	            emit_nl();
1059	        } else {
1060	            emit_str(EMIT_INDENT);
1061	            emit_str("la      r0,");
1062	            emit_int(frame_sz);
1063	            emit_nl();
1064	        }
1065	        emit_instr("sub     sp,r0");
1066	    }
1067	
1068	    /* Emit body statements */
1069	    cg_block(body);
1070	
1071	    /* Standard epilogue: mov sp,fp, pop r1, pop r2, pop fp, jmp (r1) */
1072	    emit_epilogue();
1073	}
