    int v = layout_static_next;
    int d3 = v / 4096;
    int d2 = (v / 256) % 16;
    int d1 = (v / 16) % 16;
    int d0 = v % 16;
    char hex[5];
    hex[0] = d3 < 10 ? '0' + d3 : 'A' + d3 - 10;
    hex[1] = d2 < 10 ? '0' + d2 : 'A' + d2 - 10;
    hex[2] = d1 < 10 ? '0' + d1 : 'A' + d1 - 10;
    hex[3] = d0 < 10 ? '0' + d0 : 'A' + d0 - 10;
    hex[4] = 0;
    uart_putstr(hex);
    uart_putchar(10);
}

