            errs = errs + 1;
        }
        /* Loop header label */
        if (!str_find(out, "L0:")) {
            uart_puts("  FAIL: missing loop header label (L0)");
            errs = errs + 1;
        }
        /* Comparison: cls for I > end check */
        if (!str_find(out, "cls     r1,r0")) {
            uart_puts("  FAIL: missing cls comparison (cls r1,r0)");
            errs = errs + 1;
        }
        /* Branch to end when I > end */
        if (!str_find(out, "bc      ")) {
