            uart_puts("  FAIL: missing cls comparison");
            errs = errs + 1;
        }
        /* End label */
        if (!str_find(out, "L1:")) {
            uart_puts("  FAIL: missing loop end label (L1)");
            errs = errs + 1;
        }
    }

    /* Test 3: Nested DO count and DO WHILE */
    uart_puts("--- do_count: nested with do_while ---");
